module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);

reg mul_en_out_reg;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) mul_en_out_reg <= 1'b0;
    else mul_en_out_reg <= {mul_en_out_reg[6:0], mul_en_in};
end
assign mul_en_out = mul_en_out_reg[7];
reg [7:0] mul_a_reg;
reg [7:0] mul_b_reg;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) {mul_a_reg, mul_b_reg} <= 16'd0;
    else if(mul_en_in) {mul_a_reg, mul_b_reg} <= {mul_a, mul_b};
end
wire [7:0] temp[7:0];
genvar i;
generate
    for(i=0; i<8; i=i+1) begin : gen_mux
        assign temp[i] = {8{mul_a_reg[i]}} & mul_b_reg;
    end
endgenerate
reg [15:0] sum[7:0];
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) sum[0] <= 16'd0;
    else sum[0] <= temp[0];
    for(i=1; i<8; i=i+1) begin
        if(!rst_n) sum[i] <= 16'd0;
        else if(clk) sum[i] <= temp[i] + sum[i-1];
    end
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) sum[7] <= 16'd0;
    else if(clk) sum[7] <= sum[6] + sum[7-1];
end
reg [15:0] mul_out_reg;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) mul_out_reg <= 16'd0;
    else if(clk) mul_out_reg <= sum[7];
end
assign mul_out = mul_en_out ? mul_out_reg : 16'd0;
endmodule
